<template>
  <main class="jar-page">
    <section class="jar-hero">
      <div class="hero-copy">
        <span class="eyebrow">KNOWLEDGE JAR · 个人知识资产</span><h1>知识收藏瓶</h1>
        <p>把每一次理解与掌握沉淀为可见的知识资产。完成学习阶段时系统会自动收集，你也可以在学习路径中自主收藏。</p>
        <div class="hero-actions"><el-button @click="$router.push('/profile')">返回学习画像</el-button><el-button type="primary" @click="$router.push('/path')">继续学习</el-button><el-button text :loading="loading" @click="loadJar">刷新</el-button></div>
      </div>
      <div class="jar-visual"><div class="jar-lid"></div><div class="glass-jar"><span v-for="(item,index) in displayBubbles" :key="item.knowledge_point" :style="bubbleStyle(index)">{{shortPoint(item.knowledge_point)}}</span><div v-if="!items.length" class="jar-empty-text">等待第一颗知识</div><div class="jar-fill" :style="{height:fillHeight}"></div></div><b>{{stats.total||0}} 个知识点</b></div>
    </section>
    <section class="stat-grid"><article><small>知识资产总量</small><strong>{{stats.total||0}}</strong><span>已沉淀知识点</span></article><article><small>智能沉淀</small><strong>{{stats.auto_count||0}}</strong><span>随阶段完成自动收集</span></article><article><small>自主收藏</small><strong>{{stats.manual_count||0}}</strong><span>由你主动加入收藏瓶</span></article><article><small>覆盖阶段</small><strong>{{stats.stage_count||0}}</strong><span>知识积累来源阶段</span></article></section>
    <section class="asset-panel">
      <header><div><span class="eyebrow">MY KNOWLEDGE ASSETS</span><h2>我的知识资产 <small>{{filteredItems.length}} 项</small></h2></div><div class="asset-tools"><el-radio-group v-model="sourceFilter" size="small"><el-radio-button label="all">全部</el-radio-button><el-radio-button label="auto">自动沉淀</el-radio-button><el-radio-button label="manual">主动收藏</el-radio-button></el-radio-group><el-input v-model="keyword" clearable placeholder="搜索知识点" class="asset-search" /></div></header>
      <div v-if="filteredItems.length" class="asset-grid"><article v-for="item in filteredItems" :key="item.knowledge_point" class="asset-card"><div class="asset-orb"><el-icon><MagicStick v-if="item.auto_collected"/><User v-else/></el-icon></div><div class="asset-content"><h3>{{item.knowledge_point}}</h3><p>{{item.stage_title||'个人自主学习积累'}}</p><div><span>{{item.source_label}}</span><time>{{formatTime(item.create_time)}}</time></div></div><button title="移出收藏瓶" @click="removeItem(item)">移除</button></article></div>
      <el-empty v-else :description="keyword||sourceFilter!=='all'?'没有匹配的知识资产':'收藏瓶还是空的，去学习路径完成阶段或手动收藏吧'"><el-button v-if="!keyword&&sourceFilter==='all'" type="primary" @click="$router.push('/path')">前往学习路径</el-button></el-empty>
    </section>
  </main>
</template>
<script setup>
import { computed,onMounted,ref } from 'vue';
import { ElMessage,ElMessageBox } from 'element-plus';
import { MagicStick,User } from '@element-plus/icons-vue';
import { knowledgeJarApi } from '../api';
const loading=ref(false),items=ref([]),stats=ref({}),keyword=ref(''),sourceFilter=ref('all');
const filteredItems=computed(()=>{const key=keyword.value.trim().toLowerCase();return items.value.filter(item=>{const sourceMatched=sourceFilter.value==='all'||(sourceFilter.value==='auto'?item.auto_collected:!item.auto_collected);const keywordMatched=!key||`${item.knowledge_point} ${item.stage_title} ${item.source_label}`.toLowerCase().includes(key);return sourceMatched&&keywordMatched})});
const displayBubbles=computed(()=>items.value.slice(0,12));
const fillHeight=computed(()=>`${Math.min(18+(stats.value.total||0)*3,72)}%`);
const positions=[['10%','72%'],['52%','78%'],['28%','58%'],['66%','55%'],['8%','42%'],['46%','39%'],['70%','27%'],['25%','24%'],['52%','12%'],['2%','16%'],['74%','70%'],['36%','84%']];
function bubbleStyle(index){const [left,bottom]=positions[index%positions.length];return{left,bottom,'--delay':`${index*-.35}s`}}
function shortPoint(value){const text=String(value||'');return text.length>7?`${text.slice(0,7)}…`:text}
function formatTime(value){if(!value)return'刚刚收藏';const date=new Date(value);return Number.isNaN(date.getTime())?String(value):date.toLocaleDateString('zh-CN',{month:'2-digit',day:'2-digit'})}
async function loadJar(){loading.value=true;try{const res=await knowledgeJarApi.list();if(res.code!==200)throw new Error(res.msg||'加载失败');items.value=res.data?.items||[];stats.value=res.data?.stats||{}}catch(error){ElMessage.error(error?.message||'知识收藏瓶加载失败')}finally{loading.value=false}}
async function removeItem(item){try{await ElMessageBox.confirm(`确定将“${item.knowledge_point}”移出收藏瓶吗？`,'移出知识资产',{type:'warning'});const res=await knowledgeJarApi.remove({knowledge_point:item.knowledge_point});if(res.code!==200)throw new Error(res.msg||'移出失败');await loadJar();ElMessage.success('已从收藏瓶移出')}catch(error){if(error!=='cancel'&&error!=='close')ElMessage.error(error?.message||'移出失败')}}
onMounted(loadJar);
</script>
