-shadow:0 7px 16px rgba(25,124,111,.18);color:#fff;font-size:10px;font-weight:800;text-align:center;animation:float 4.6s ease-in-out var(--delay) infinite}.jar-empty-text{position:absolute;inset:0;display:grid;place-items:center;color:#78918e;font-size:13px}.jar-visual>b{margin-top:13px;color:#32665f}.stat-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:14px}.stat-grid article{padding:22px;border:1px solid #deebe9;border-radius:22px;background:#fff;box-shadow:0 10px 25px rgba(31,70,69,.04)}.stat-grid small,.stat-grid span{display:block;color:#78909d}.stat-grid strong{display:block;margin:8px 0 5px;color:#167f70;font-size:32px}.stat-grid span{font-size:12px}.asset-panel{min-height:360px;padding:30px;border:1px solid #e1e9ef;border-radius:28px;background:#fff;box-shadow:0 14px 36px rgba(15,35,60,.05)}.asset-panel>header{display:flex;align-items:flex-end;justify-content:space-between;gap:18px;margin-bottom:22px}.asset-panel h2{margin:8px 0 0;font-size:26px}.asset-search{width:310px}.asset-search :deep(.el-input__wrapper){border-radius:13px}.asset-grid{display:grid;grid-template-columns:repeat(2,minmax(0,1fr));gap:14px}.asset-card{display:grid;grid-template-columns:52px minmax(0,1fr) auto;align-items:center;gap:14px;padding:17px;border:1px solid #e0ecea;border-radius:18px;background:linear-gradient(135deg,#fbfefd,#f5fbfa);transition:.2s}.asset-card:hover{transform:translateY(-2px);border-color:#83cfc1;box-shadow:0 12px 24px rgba(33,126,110,.08)}.asset-orb{display:grid;width:50px;height:50px;place-items:center;border-radius:17px;background:linear-gradient(135deg,#5ed3ba,#188f7c);box-shadow:0 8px 18px rgba(24,143,124,.18);color:#fff;font-size:12px;font-weight:900}.asset-content{min-width:0}.asset-content h3{margin:0;color:#16324a;font-size:16px}.asset-content p{margin:6px 0;color:#69808f;font-size:12px}.asset-content div{display:flex;gap:10px;color:#188f7c;font-size:11px}.asset-content time{color:#94a3ad}.asset-card button{padding:6px 9px;border:0;border-radius:9px;background:transparent;color:#8a9aa5;cursor:pointer}.asset-card button:hover{background:#fff0f0;color:#d45858}@keyframes float{50%{transform:translateY(-7px) rotate(2deg)}}@media(max-width:1100px){.jar-hero{grid-template-columns:1fr 310px;padding:34px}.stat-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:760px){.jar-hero{grid-template-columns:1fr;padding:28px}.hero-copy h1{font-size:34px}.asset-panel>header{align-items:stretch;flex-direction:column}.asset-search{width:100%}.asset-grid,.stat-grid{grid-template-columns:1fr}}
</style>
